 1	import { SortByDirection, Table, Tbody, Tr } from '@patternfly/react-table';
 2	import { fireEvent, render } from '@testing-library/react';
 3	import * as React from 'react';
 4	import { Column, ColumnsId, ColumnSizeMap } from '../../../../utils/columns';
 5	import {
 6	  AllSelectedColumnSample,
 7	  DefaultColumnSample,
 8	  filterOrderedColumnsByIds
 9	} from '../../../__tests-data__/columns';
10	import { NetflowTableHeader } from '../netflow-table-header';
11	
12	const NetflowTableHeaderWrapper: React.FC<{
13	  onSort: (id: ColumnsId, direction: SortByDirection) => void;
14	  sortId: ColumnsId;
15	  sortDirection: SortByDirection;
16	  columns: Column[];
17	  setColumns: (v: Column[]) => void;
18	  columnSizes: ColumnSizeMap;
19	  setColumnSizes: (v: ColumnSizeMap) => void;
20	}> = ({ onSort, sortId, sortDirection, columns, setColumns, columnSizes, setColumnSizes }) => {
21	  return (
22	    <Table aria-label="Misc table" variant="compact">
23	      <NetflowTableHeader
24	        onSort={onSort}
25	        sortDirection={sortDirection}
26	        sortId={sortId}
27	        columns={columns}
28	        setColumns={setColumns}
29	        columnSizes={columnSizes}
30	        setColumnSizes={setColumnSizes}
31	        tableWidth={100}
32	      />
33	      <Tbody><Tr /></Tbody>
34	    </Table>
35	  );
36	};
37	
38	describe('<NetflowTableHeader />', () => {
39	  const mocks = {
40	    onSort: jest.fn(),
41	    sortId: ColumnsId.endtime,
42	    sortDirection: SortByDirection.asc,
43	    tableWidth: 100,
44	    setColumns: jest.fn(),
45	    columnSizes: {},
46	    setColumnSizes: jest.fn()
47	  };
48	
49	  it('should render component', async () => {
50	    const { container } = render(<NetflowTableHeaderWrapper {...mocks} columns={AllSelectedColumnSample} />);
51	    expect(container.querySelectorAll('thead')).toHaveLength(1);
52	    expect(container.querySelectorAll('th').length).toBeGreaterThanOrEqual(AllSelectedColumnSample.length);
53	  });
54	
55	  it('should render given columns', async () => {
56	    const { container } = render(
57	      <NetflowTableHeaderWrapper {...mocks} columns={filterOrderedColumnsByIds([ColumnsId.endtime])} />
58	    );
59	    expect(container.querySelectorAll('thead')).toHaveLength(1);
60	    expect(container.querySelectorAll('thead tr')).toHaveLength(1);
61	    expect(container.querySelectorAll('th')).toHaveLength(1);
62	  });
63	
64	  it('should call sort function on click', async () => {
65	    const { container } = render(<NetflowTableHeaderWrapper {...mocks} columns={DefaultColumnSample} />);
66	    const firstButton = container.querySelector('button')!;
67	    fireEvent.click(firstButton);
68	    expect(mocks.onSort).toHaveBeenCalledWith('StartTime', 'asc');
69	  });
70	
71	  it('should nested consecutive group columns', async () => {
72	    const selectedIds = [ColumnsId.endtime, ColumnsId.srcname, ColumnsId.srcport, ColumnsId.dstname, ColumnsId.packets];
73	    const { container } = render(
74	      <NetflowTableHeaderWrapper {...mocks} columns={filterOrderedColumnsByIds(selectedIds)} />
75	    );
76	    expect(container.querySelectorAll('thead')).toHaveLength(1);
77	    expect(container.querySelectorAll('thead tr')).toHaveLength(2);
78	    expect(container.querySelectorAll('th').length).toBeGreaterThanOrEqual(selectedIds.length);
79	  });
80	
81	  it('should keep flat non consecutive group columns', async () => {
82	    const selectedIds = [ColumnsId.endtime, ColumnsId.srcname, ColumnsId.dstname, ColumnsId.packets, ColumnsId.srcport];
83	    const { container } = render(
84	      <NetflowTableHeaderWrapper {...mocks} columns={filterOrderedColumnsByIds(selectedIds)} />
85	    );
86	    expect(container.querySelectorAll('thead')).toHaveLength(1);
87	    expect(container.querySelectorAll('thead tr')).toHaveLength(1);
88	    expect(container.querySelectorAll('th')).toHaveLength(selectedIds.length);
89	  });
90	});

